#include <bits/stdc++.h>
using namespace std;

int timeToPublishComicBooks(int x, int y, int z, int k, vector<int> &printMachine) {
    priority_queue<pair<int, int>, vector<pair<int, int>>, greater<pair<int, int>>> printing;
    priority_queue<int, vector<int>, greater<int>> binding;
    int answer = 0;

    for (int i = 0; i < y; i++) {
        printing.push({printMachine[i], printMachine[i]});
    }

    for (int i = 0; i < z; i++) {
        binding.push(0);
    }

    for (int i = 1; i <= x; i++) {
        auto printingMachine = printing.top();
        printing.pop();
        int printingEndAt = printingMachine.first;
        int timeToPrint = printingMachine.second;

        printing.push({printingEndAt + timeToPrint, timeToPrint});

        int bindingMachine = binding.top();
        binding.pop();

        int bindingStartAt = max(printingEndAt, bindingMachine);
        int bindingEndAt = bindingStartAt + k;

        binding.push(bindingEndAt);
        answer = bindingEndAt;
    }

    return answer;
}

int main() {
    int t;
    cin >> t;
    while(t--) {
        int x, y, z, k;
        cin >> x >> y >> z >> k;

        vector<int> printMachine(y);
        for(int i = 0; i < y; i++) {
            cin >> printMachine[i];
        }

        cout << timeToPublishComicBooks(x, y, z, k, printMachine) << "\n";
    }
    return 0;
}
